import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AdminStats } from '../../core/models';

/** Admin dashboard — aggregate counts only (no per-return access). */
@Component({
  selector: 'app-admin-stats',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './admin-stats.component.html',
  styleUrl: './admin-stats.component.css',
})
export class AdminStatsComponent {
  loading = signal<boolean>(false);
  error = signal<string>('');

  // Mock data — service_agent clears this and loads via ApiService.getAdminStats().
  stats = signal<AdminStats>({
    userCount: 128,
    returnCount: 214,
    draftCount: 96,
    completeCount: 118,
  });

  get cards() {
    const s = this.stats();
    return [
      { label: 'Users', value: s.userCount, icon: '👥' },
      { label: 'Returns', value: s.returnCount, icon: '📄' },
      { label: 'Drafts', value: s.draftCount, icon: '✏️' },
      { label: 'Completed', value: s.completeCount, icon: '✅' },
    ];
  }
}
